editorial:
**Setup**: Let MOD = 10^9 + 7. `dp[i]` = number of decodings of prefix length `i`.

**Single-char count for `s[i-1]`**:
- '*' → 9 (1..9).
- '0' → 0.
- else (1..9) → 1.

**Two-char count for `s[i-2..i-1]`**:
- ** → 15 (10..19 plus 21..26 = 9 + 6 = 15).
- *X (X digit): if X==0, 2 (10, 20); X in 1..6 → 2 (1X, 2X); X in 7..9 → 1 (1X only).
- X* (X digit): if X=='1', 9 (10..19); X=='2', 6 (21..26); else 0.
- XY (both digits): 1 if 10..26 else 0.

```javascript
function decodeWaysStar(s) {
  const MOD = 1000000007n;
  const n = s.length;
  let prev2 = 1n, prev1 = single(s[0]);
  if (n === 1) return Number(prev1);
  for (let i = 2; i <= n; i++) {
    const a = single(s[i-1]);
    const b = pair(s[i-2], s[i-1]);
    const cur = (a * prev1 + b * prev2) % MOD;
    prev2 = prev1; prev1 = cur;
  }
  return Number(prev1);
  function single(ch) {
    if (ch === '*') return 9n;
    if (ch === '0') return 0n;
    return 1n;
  }
  function pair(a, b) {
    if (a === '*' && b === '*') return 15n;
    if (a === '*') {
      if (b === '0') return 2n;
      if (b >= '1' && b <= '6') return 2n;
      return 1n;
    }
    if (b === '*') {
      if (a === '1') return 9n;
      if (a === '2') return 6n;
      return 0n;
    }
    const v = parseInt(a + b, 10);
    return (v >= 10 && v <= 26) ? 1n : 0n;
  }
}
```

**Time**: O(n). **Space**: O(1).

BigInt used to dodge overflow when multiplying large counts before modding.

